/* -------------------------------------------------------------------------
 * 1. Custom Post Types
 * ---------------------------------------------------------------------- */
add_action('init', function () {
    $common = [
        'public'       => true,
        'show_ui'      => true,
        'show_in_rest' => true,
        'has_archive'  => false,
        'supports'     => ['title', 'editor', 'thumbnail', 'excerpt', 'custom-fields'],
    ];

    register_post_type('product', array_merge($common, [
        'labels'    => ['name' => 'Products', 'singular_name' => 'Product'],
        'rest_base' => 'product',
        'menu_icon' => 'dashicons-archive',
    ]));

    register_post_type('solution', array_merge($common, [
        'labels'    => ['name' => 'Solutions', 'singular_name' => 'Solution'],
        'rest_base' => 'solution',
        'menu_icon' => 'dashicons-lightbulb',
    ]));

    register_post_type('case-study', array_merge($common, [
        'labels'    => ['name' => 'Case Studies', 'singular_name' => 'Case Study'],
        'rest_base' => 'case-study',
        'menu_icon' => 'dashicons-portfolio',
    ]));

    register_post_type('testimonial', array_merge($common, [
        'labels'    => ['name' => 'Testimonials', 'singular_name' => 'Testimonial'],
        'rest_base' => 'testimonial',
        'menu_icon' => 'dashicons-format-quote',
    ]));

    register_post_type('partner', array_merge($common, [
        'labels'    => ['name' => 'Partners', 'singular_name' => 'Partner'],
        'rest_base' => 'partner',
        'menu_icon' => 'dashicons-groups',
    ]));

    /* ---------------------------------------------------------------------
     * 2. product-category taxonomy (attached to the product CPT)
     *    REST: /wp/v2/product-category returns the category terms;
     *    products embed their term via ?_embed (wp:term).
     * ------------------------------------------------------------------ */
    register_taxonomy('product-category', ['product'], [
        'labels'            => ['name' => 'Product Categories', 'singular_name' => 'Product Category'],
        'public'            => true,
        'hierarchical'      => true,
        'show_ui'           => true,
        'show_admin_column' => true,
        'show_in_rest'      => true,
        'rest_base'         => 'product-category',
    ]);
});

/* -------------------------------------------------------------------------
 * 3. ACF field groups (registered in code so no manual clicking is needed).
 *    Guarded so the site never fatals if ACF is briefly inactive.
 * ---------------------------------------------------------------------- */
add_action('acf/init', function () {
    if (!function_exists('acf_add_local_field_group')) {
        return;
    }

    $text     = fn($key, $name, $label) => ['key' => $key, 'name' => $name, 'label' => $label, 'type' => 'text'];
    $textarea = fn($key, $name, $label) => ['key' => $key, 'name' => $name, 'label' => $label, 'type' => 'textarea'];
    $wysiwyg  = fn($key, $name, $label) => ['key' => $key, 'name' => $name, 'label' => $label, 'type' => 'wysiwyg', 'media_upload' => 1];
    $number   = fn($key, $name, $label) => ['key' => $key, 'name' => $name, 'label' => $label, 'type' => 'number'];

    // --- Product ---------------------------------------------------------
    acf_add_local_field_group([
        'key'      => 'group_gvd_product',
        'title'    => 'Product Details',
        'show_in_rest' => 1,
        'location' => [[['param' => 'post_type', 'operator' => '==', 'value' => 'product']]],
        'fields'   => [
            $text('field_gvd_p_shortdesc', 'shortDescription', 'Short Description'),
            $wysiwyg('field_gvd_p_desc', 'description', 'Full Description'),
            $number('field_gvd_p_order', 'displayOrder', 'Display Order'),
            [
                'key' => 'field_gvd_p_features', 'name' => 'features', 'label' => 'Features',
                'type' => 'repeater', 'layout' => 'block', 'button_label' => 'Add feature',
                'sub_fields' => [
                    $text('field_gvd_p_feat_title', 'title', 'Title'),
                    $textarea('field_gvd_p_feat_desc', 'description', 'Description'),
                ],
            ],
            [
                'key' => 'field_gvd_p_specs', 'name' => 'specifications', 'label' => 'Specifications',
                'type' => 'repeater', 'layout' => 'table', 'button_label' => 'Add spec',
                'sub_fields' => [
                    $text('field_gvd_p_spec_key', 'key', 'Spec'),
                    $text('field_gvd_p_spec_val', 'value', 'Value'),
                ],
            ],
        ],
    ]);

    // --- Solution --------------------------------------------------------
    acf_add_local_field_group([
        'key'      => 'group_gvd_solution',
        'title'    => 'Solution Details',
        'show_in_rest' => 1,
        'location' => [[['param' => 'post_type', 'operator' => '==', 'value' => 'solution']]],
        'fields'   => [
            $text('field_gvd_s_shortdesc', 'shortDescription', 'Short Description'),
            $wysiwyg('field_gvd_s_desc', 'description', 'Full Description'),
            $number('field_gvd_s_order', 'displayOrder', 'Display Order'),
            [
                'key' => 'field_gvd_s_challenges', 'name' => 'challenges', 'label' => 'Challenges',
                'type' => 'repeater', 'layout' => 'block', 'button_label' => 'Add challenge',
                'sub_fields' => [
                    $text('field_gvd_s_ch_title', 'title', 'Title'),
                    $textarea('field_gvd_s_ch_desc', 'description', 'Description'),
                ],
            ],
            [
                'key' => 'field_gvd_s_caps', 'name' => 'capabilities', 'label' => 'Capabilities',
                'type' => 'repeater', 'layout' => 'block', 'button_label' => 'Add capability',
                'sub_fields' => [
                    $text('field_gvd_s_cap_title', 'title', 'Title'),
                    $textarea('field_gvd_s_cap_desc', 'description', 'Description'),
                ],
            ],
            [
                'key' => 'field_gvd_s_outcomes', 'name' => 'businessOutcomes', 'label' => 'Business Outcomes',
                'type' => 'repeater', 'layout' => 'block', 'button_label' => 'Add outcome',
                'sub_fields' => [
                    $text('field_gvd_s_out_title', 'title', 'Title'),
                    $textarea('field_gvd_s_out_desc', 'description', 'Description'),
                    $text('field_gvd_s_out_metric', 'metric', 'Metric (e.g. 40% faster)'),
                ],
            ],
        ],
    ]);

    // --- Case Study ------------------------------------------------------
    acf_add_local_field_group([
        'key'      => 'group_gvd_casestudy',
        'title'    => 'Case Study Details',
        'show_in_rest' => 1,
        'location' => [[['param' => 'post_type', 'operator' => '==', 'value' => 'case-study']]],
        'fields'   => [
            $text('field_gvd_cs_industry', 'industry', 'Industry'),
            $text('field_gvd_cs_client', 'clientName', 'Client Name'),
            $wysiwyg('field_gvd_cs_challenge', 'challenge', 'Challenge'),
            $wysiwyg('field_gvd_cs_solution', 'solution', 'Solution'),
            $wysiwyg('field_gvd_cs_results', 'results', 'Results'),
            $textarea('field_gvd_cs_quote', 'quote', 'Quote'),
            $text('field_gvd_cs_qperson', 'quotedPerson', 'Quoted Person'),
            $text('field_gvd_cs_qrole', 'quotedRole', 'Quoted Role'),
        ],
    ]);

    // --- Testimonial -----------------------------------------------------
    acf_add_local_field_group([
        'key'      => 'group_gvd_testimonial',
        'title'    => 'Testimonial Details',
        'show_in_rest' => 1,
        'location' => [[['param' => 'post_type', 'operator' => '==', 'value' => 'testimonial']]],
        'fields'   => [
            $textarea('field_gvd_t_quote', 'quote', 'Quote'),
            $text('field_gvd_t_author', 'author', 'Author'),
            $text('field_gvd_t_role', 'role', 'Role'),
            $text('field_gvd_t_company', 'company', 'Company'),
            ['key' => 'field_gvd_t_home', 'name' => 'displayOnHome', 'label' => 'Show on Home', 'type' => 'true_false', 'ui' => 1],
        ],
    ]);

    // --- Partner ---------------------------------------------------------
    acf_add_local_field_group([
        'key'      => 'group_gvd_partner',
        'title'    => 'Partner Details',
        'show_in_rest' => 1,
        'location' => [[['param' => 'post_type', 'operator' => '==', 'value' => 'partner']]],
        'fields'   => [
            ['key' => 'field_gvd_pa_website', 'name' => 'website', 'label' => 'Website', 'type' => 'url'],
            ['key' => 'field_gvd_pa_home', 'name' => 'displayOnHome', 'label' => 'Show on Home', 'type' => 'true_false', 'ui' => 1],
        ],
    ]);

    // --- Product Category (taxonomy term fields) -------------------------
    acf_add_local_field_group([
        'key'      => 'group_gvd_productcat',
        'title'    => 'Product Category Details',
        'show_in_rest' => 1,
        'location' => [[['param' => 'taxonomy', 'operator' => '==', 'value' => 'product-category']]],
        'fields'   => [
            $text('field_gvd_pc_shortdesc', 'shortDescription', 'Short Description'),
            $number('field_gvd_pc_order', 'displayOrder', 'Display Order'),
        ],
    ]);
});

/* -------------------------------------------------------------------------
 * 4. REST routes: form submissions + site-global settings
 * ---------------------------------------------------------------------- */
add_action('rest_api_init', function () {
    register_rest_route('gvd/v1', '/form-submissions', [
        'methods'             => 'POST',
        'permission_callback' => '__return_true',
        'callback'            => function (WP_REST_Request $req) {
            $data = $req->get_json_params();
            if (empty($data) || empty($data['email'])) {
                return new WP_Error('gvd_invalid', 'Missing required fields', ['status' => 422]);
            }
            wp_insert_post([
                'post_type'    => 'gvd_submission',
                'post_status'  => 'private',
                'post_title'   => 'Form submission ' . current_time('Y-m-d H:i'),
                'post_content' => wp_json_encode($data, JSON_PRETTY_PRINT),
            ]);
            wp_mail(
                get_option('admin_email'),
                'New website form submission',
                print_r($data, true)
            );
            return ['ok' => true];
        },
    ]);

    register_rest_route('gvd/v1', '/global', [
        'methods'             => 'GET',
        'permission_callback' => '__return_true',
        'callback'            => function () {
            // Frontend's getGlobal() reads the `acf` object. Pull from an ACF
            // options page if present (ACF Pro), else fall back to core options.
            $acf = function_exists('get_fields') ? (get_fields('options') ?: []) : [];
            return [
                'acf' => array_merge([
                    'siteName'        => get_bloginfo('name'),
                    'siteDescription' => get_bloginfo('description'),
                    'contactEmail'    => get_option('admin_email'),
                ], is_array($acf) ? $acf : []),
            ];
        },
    ]);
});

// Store form submissions as a private CPT visible in wp-admin.
add_action('init', function () {
    register_post_type('gvd_submission', [
        'public'   => false,
        'show_ui'  => true,
        'labels'   => ['name' => 'Form Submissions', 'singular_name' => 'Form Submission'],
        'supports' => ['title', 'editor'],
    ]);
});

/* -------------------------------------------------------------------------
 * 5. CORS — allow the Next.js frontend origins to call the REST API.
 *    (Server-side page fetches don't need this; the browser contact form does.)
 * ---------------------------------------------------------------------- */
add_action('rest_api_init', function () {
    remove_filter('rest_pre_serve_request', 'rest_send_cors_headers');
    add_filter('rest_pre_serve_request', function ($value) {
        $allowed = [
            'https://geniusvision.ae',
            'https://www.geniusvision.ae',
            'https://geniusvision.in',
            'https://www.geniusvision.in',
            'http://localhost:3000',
        ];
        $origin = $_SERVER['HTTP_ORIGIN'] ?? '';
        if (in_array($origin, $allowed, true)) {
            header('Access-Control-Allow-Origin: ' . $origin);
            header('Access-Control-Allow-Methods: GET, POST, OPTIONS');
            header('Access-Control-Allow-Headers: Content-Type, Authorization');
            header('Vary: Origin');
        }
        return $value;
    });
}, 15);
